app.get('/health', (req, res) => {
  if (!TRUSTED_CIDRS.some(cidr => req.ip.startsWith(cidr.split('/')[0]))) {
    return res.status(404).end(); // Don't confirm service existence
  }
  res.json({ status: 'ok' });
});
```

