  const { rows } = await pool.query('SELECT id, name, email FROM users');
  return rows;
}

app.get('/users', requireAuth, async (req, res, next) => {
  try {
    res.json(await getUsers());
  } catch (err) {
    next(err); // centralized error handler (see Finding #7)
  }
});
```

